const post = $json;

// 디버깅: 실제 데이터 구조 확인
const contentRaw = post.content?.raw || '';
const contentRendered = post.content?.rendered || '';
const contentDirect = post.content || '';
const title = post.title?.raw || post.title?.rendered || post.title || '';

// 가능한 모든 콘텐츠 소스 시도
let content = contentRaw || contentRendered;
if (!content && typeof contentDirect === 'string') {
  content = contentDirect;
}

// 디버깅 정보 포함하여 무조건 통과
return { json: { skip: false, id: post.id, title: title, content: content, debug: { hasRaw: !!contentRaw, hasRendered: !!contentRendered, contentLength: content.length, contentType: typeof post.content } } };

const sourceData = $items('Build Fix Prompt')[$itemIndex]?.json || {};
const aiResponse = $json;

function extractJson(text) {
  const cleaned = String(text || '').replace(/^```json\s*/i, '').replace(/```$/i, '').trim();
  const first = cleaned.indexOf('{');
  const last = cleaned.lastIndexOf('}');
  if (first === -1 || last === -1) throw new Error('No JSON found');
  return JSON.parse(cleaned.slice(first, last + 1));
}

try {
  const result = extractJson(aiResponse.choices?.[0]?.message?.content || '');

  // AI가 수정 불필요하다고 판단하면 스킵
  if (!result.needs_fix || !result.fixed_content) {
    return { json: { skip: true, reason: 'AI determined no fix needed', id: sourceData.id, title: sourceData.title, lists_fixed: 0 } };
  }

  // 수정 필요한 경우 skip: false 명시적으로 설정
  return { json: { skip: false, id: sourceData.id, title: sourceData.title, fixed_content: result.fixed_content, lists_fixed: result.lists_fixed || 0 } };
} catch (e) {
  return { json: { skip: true, error: e.message, id: sourceData.id, title: sourceData.title } };
}

const updateResult = $json;
const fixData = $items('IF Has Fixed Content')[$itemIndex]?.json || {};

return { json: { status: 'updated', id: fixData.id, title: fixData.title, lists_fixed: fixData.lists_fixed, wp_status: updateResult.status } };
